import{_ as t,o as s,c as n,a2 as e}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"角色状态","description":"","frontmatter":{},"headers":[],"relativePath":"guide/characters-states.md","filePath":"guide/characters-states.md","lastUpdated":1781182504000}'),r={name:"guide/characters-states.md"};function d(p,a,o,l,i,h){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="角色状态" tabindex="-1">角色状态 <a class="header-anchor" href="#角色状态" aria-label="Permalink to &quot;角色状态&quot;">​</a></h1><p>角色状态是对于行动顺序表而言的行动状态，优先级最高，决定了角色是否可以行动。</p><h2 id="状态类型" tabindex="-1">状态类型 <a class="header-anchor" href="#状态类型" aria-label="Permalink to &quot;状态类型&quot;">​</a></h2><h3 id="控制态" tabindex="-1">控制态 <a class="header-anchor" href="#控制态" aria-label="Permalink to &quot;控制态&quot;">​</a></h3><p>影响角色行动和决策的状态，高级别覆盖低级别：</p><table tabindex="0"><thead><tr><th>状态</th><th>效果</th><th>允许操作</th></tr></thead><tbody><tr><td><strong>完全行动不能</strong></td><td>回合被跳过</td><td>无</td></tr><tr><td><strong>行动受限</strong></td><td>决策受限</td><td>仅特殊物品</td></tr><tr><td><strong>战斗不能</strong></td><td>无法战斗</td><td>仅物品</td></tr><tr><td><strong>技能受限</strong></td><td>无法使用技能</td><td>普攻 + 物品</td></tr><tr><td><strong>攻击受限</strong></td><td>无法普攻</td><td>技能 + 物品</td></tr></tbody></table><blockquote><p>当同时存在技能受限和攻击受限时，被<strong>战斗不能</strong>覆盖。</p></blockquote><h3 id="吟唱态" tabindex="-1">吟唱态 <a class="header-anchor" href="#吟唱态" aria-label="Permalink to &quot;吟唱态&quot;">​</a></h3><p>归行动顺序表管理：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><strong>吟唱中</strong></td><td>正在吟唱魔法，行动阶段自动结算，无法手动决策</td></tr><tr><td><strong>预释放爆发技</strong></td><td>已预释放爆发技，需选择目标，无法取消或执行其他行动</td></tr></tbody></table><p>吟唱中被施加控制态（攻击受限除外）→ 打断施法，取消吟唱态。</p><p>预释放爆发技是<strong>最高级别</strong>状态，无法被任何状态覆盖（除非死亡）。</p><h3 id="常态" tabindex="-1">常态 <a class="header-anchor" href="#常态" aria-label="Permalink to &quot;常态&quot;">​</a></h3><p>允许角色自主决策，这是默认状态。</p><h2 id="状态覆盖优先级" tabindex="-1">状态覆盖优先级 <a class="header-anchor" href="#状态覆盖优先级" aria-label="Permalink to &quot;状态覆盖优先级&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>预释放爆发技</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>完全行动不能</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>行动受限</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>战斗不能</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>技能受限 / 攻击受限</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>吟唱中（可被打断）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>常态</span></span></code></pre></div>`,16)])])}const g=t(r,[["render",d]]);export{b as __pageData,g as default};
